```ts
function handle(x: any) { return x.foo.bar }   // BAD: no check at all
function handle(x: unknown) {
  if (typeof x === 'object' && x && 'foo' in x) return (x as {foo: {bar: string}}).foo.bar
}
```

```ts
import { z } from 'zod'
const User = z.object({ name: z.string(), age: z.number() })
const u = User.parse(await fetch('/u').then(r => r.json()))
// u is typed AND validated; throws on bad data
```

